      }
    }

    /* \u2500\u2500 Reset & base \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

    html { font-size: 16px; }

    body {
      background: var(--c-page);
      color: var(--c-ink);
      font-family: 'DM Sans', -apple-system, BlinkMacSystemFont, 'Segoe UI',
                   'Noto Sans', Helvetica, Arial, sans-serif;
      font-size: 14px;
      line-height: 1.5;
      -webkit-font-smoothing: antialiased;
      -moz-osx-font-smoothing: grayscale;
    }

    /* \u2500\u2500 Layout \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */
    .page-wrap {
      min-height: 100vh;
      padding: 20px 16px 56px;
    }

    .content {
      max-width: var(--content-width);
      margin: 0 auto;
    }

    .section-stack {
      display: flex;
      flex-direction: column;
      gap: var(--sp-3);
    }

    .section-group {
      display: flex;
      flex-direction: column;
      gap: var(--sp-3);
    }

    .section-group + .section-group,
    .section-group + .section-stack {
      margin-top: var(--sp-6);
    }

    .section-stack + .section-group,
    .section-stack + .section-stack {
      margin-top: var(--sp-6);
    }

    /* \u2500\u2500 Section heading (GitHub Primer UnderlineNav style) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */
    .section-heading {
      font-size: 11px;
      font-weight: 700;
      letter-spacing: 0.06em;
      text-transform: uppercase;
      color: var(--c-muted);
      padding-bottom: var(--sp-2);
      border-bottom: 2px solid var(--c-outline);
      margin-bottom: var(--sp-1);
    }

    /* \u2500\u2500 Card \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */
    .card {
      background: var(--c-surface);
      border: 1px solid var(--c-outline);
      border-radius: var(--card-radius);
      padding: var(--card-padding);
      box-shadow: 0 1px 2px var(--c-shadow);
    }

    .card + .card { margin-top: 0; } /* gaps handled by flex parent */

    .card--top {
      border-top-width: 3px;
    }

    .card--left {
      border-left-width: 3px;
    }

    .card--hero {
      background: linear-gradient(160deg, var(--c-hero-start) 0%, var(--c-hero-end) 100%);
      border-color: rgba(255,255,255,0.08);
    }

    .card--surface-variant {
      background: var(--c-surface-variant);
      border-color: var(--c-outline-muted);
      box-shadow: none;
    }

    /* \u2500\u2500 Card internals \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */
    .card-overline {
      font-size: 11px;
      font-weight: 600;
      letter-spacing: 0.06em;
      text-transform: uppercase;
      color: var(--c-subtle);
      margin-bottom: 4px;
    }

    .card-headline {
      font-size: 18px;
      font-weight: 600;
      line-height: 1.24;
      letter-spacing: -0.01em;
      color: var(--c-ink);
    }

    .card-headline--lg {
      font-size: 22px;
      letter-spacing: -0.02em;
    }

    .card-body {
      font-size: 13px;
      line-height: 1.55;
      color: var(--c-muted);
    }

    .card-divider {
      border: none;
      border-top: 1px solid var(--c-outline);
      margin: 14px 0;
    }

    /* \u2500\u2500 Hero card internals \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */
    .hero-brand {
      display: flex;
      align-items: center;
      justify-content: space-between;
      margin-bottom: 12px;
    }

    .hero-brand-left {
      display: flex;
      align-items: center;
      gap: 8px;
    }

    .hero-brand-name {
      font-size: 12px;
      font-weight: 700;
      letter-spacing: 0.12em;
      text-transform: uppercase;
      color: #ffffff;
    }

    .hero-location {
      font-size: 12px;
      color: rgba(255,255,255,0.38);
    }

    .hero-divider {
      border: none;
      border-top: 1px solid rgba(255,255,255,0.10);
      margin: 14px 0;
    }

    .hero-score-row {
      display: grid;
      grid-template-columns: auto 1fr;
      gap: 16px;
      align-items: start;
    }

    .hero-score-block {
      min-width: 80px;
    }

    .hero-score-number {
      font-size: 64px;
      font-weight: 700;
      line-height: 1;
      letter-spacing: -0.04em;
      color: var(--c-brand);
    }

    .hero-score-denom {
      font-size: 10px;
      font-weight: 600;
      letter-spacing: 0.09em;
      text-transform: uppercase;
      color: rgba(255,255,255,0.35);
      margin-top: 4px;
    }

    .hero-detail {
      border-left: 1px solid rgba(255,255,255,0.10);
      padding-left: 16px;
    }

    .hero-grade {
      font-size: 17px;
      font-weight: 700;
      letter-spacing: 0.02em;
      text-transform: uppercase;
      color: #ffffff;
    }

    .hero-window-label {
      font-size: 13px;
      font-weight: 600;
      line-height: 1.5;
      color: rgba(255,255,255,0.70);
      margin-top: 8px;
    }

    .hero-window-range {
      font-size: 12px;
      font-weight: 400;
      color: rgba(255,255,255,0.45);
    }

    .hero-date {
      font-size: 11px;
      color: rgba(255,255,255,0.38);
      margin-top: 10px;
    }

    /* \u2500\u2500 Stat grid (Carbon-inspired 2-col grid) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */
    .stat-grid {
      display: grid;
      grid-template-columns: 1fr 1fr;
      background: rgba(255,255,255,0.07);
      border: 1px solid rgba(255,255,255,0.10);
      border-radius: 8px;
      overflow: hidden;
      margin-top: 6px;
    }

    .stat-grid--light {
      background: var(--c-surface-variant);
      border-color: var(--c-outline);
    }

    .stat-cell {
      padding: 10px 12px;
    }

    .stat-cell + .stat-cell {
      border-left: 1px solid rgba(255,255,255,0.12);
    }

    .stat-grid--light .stat-cell + .stat-cell {
      border-left-color: var(--c-outline);
    }

    .stat-label {
      font-size: 11px;
      font-weight: 600;
      letter-spacing: 0.04em;
      text-transform: uppercase;
      color: rgba(255,255,255,0.7);
    }

    .stat-grid--light .stat-label {
      color: var(--c-subtle);
    }

    .stat-value {
      font-size: 15px;
      font-weight: 600;
      line-height: 1.3;
      color: #ffffff;
      margin-top: 4px;
    }

    .stat-grid--light .stat-value {
      color: var(--c-ink);
    }

    /* \u2500\u2500 Pill \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */
    .pill {
      display: inline-block;
      padding: 4px 12px;
      border-radius: 20px;
      border-width: 1px;
      border-style: solid;
      font-size: 12px;
      font-weight: 600;
      line-height: 1.4;
      white-space: nowrap;
    }

    /* \u2500\u2500 Chip \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */
    .chip {
      display: inline-block;
      margin: 2px 4px 2px 0;
      padding: 3px 8px;
      border-radius: 6px;
      background: var(--c-surface-variant);
      border: 1px solid var(--c-outline);
      font-size: 11px;
      line-height: 1.4;
      color: var(--c-ink);
      white-space: nowrap;
    }

    .chip-label {
      font-weight: 600;
    }

    /* \u2500\u2500 Score pill variants (Primer semantic colours) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */
    .score-excellent { color: #047857; background: #d1fae5; border-color: #A3D9B1; }
    .score-good      { color: #1d4ed8; background: #dbeafe; border-color: #A8D4FB; }
    .score-marginal  { color: #92400e; background: #fef3c7; border-color: #EDD17B; }
    .score-poor      { color: #991b1b; background: #fee2e2; border-color: #ECACA5; }

    @media (prefers-color-scheme: dark) {
      .score-excellent { color: #34d399; background: #064e3b; border-color: #065f46; }
      .score-good      { color: #93c5fd; background: #1e3a8a; border-color: #1e40af; }
      .score-marginal  { color: #fbbf24; background: #451a03; border-color: #78350f; }
      .score-poor      { color: #f87171; background: #7f1d1d; border-color: #991b1b; }
    }

    /* \u2500\u2500 Chip group \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */
    .chip-row {
      display: flex;
      flex-wrap: wrap;
      gap: 4px;
      align-items: center;
    }

    /* \u2500\u2500 Inline text metrics (Carbon dot-separated) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */
    .metric-run {
      font-size: 13px;
      line-height: 1.5;
      color: var(--c-ink);
    }

    .metric-run-sep {
      color: var(--c-subtle);
      padding: 0 3px;
    }

    /* \u2500\u2500 Hourly table (kept as proper table for tabular data) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */
    .hourly-table {
      width: 100%;
      border-collapse: collapse;
      font-size: 12px;
    }

    .hourly-table caption {
      font-size: 0;
      line-height: 0;
      visibility: hidden;
      caption-side: top;
    }

    .hourly-table th {
      padding: 6px 8px;
      border-bottom: 2px solid var(--c-outline);
      font-size: 11px;
      font-weight: 600;
      letter-spacing: 0.04em;
      text-transform: uppercase;
      color: var(--c-muted);
      text-align: left;
      white-space: nowrap;
    }

    .hourly-table td {
      padding: 6px 8px;
      color: var(--c-ink);
      white-space: nowrap;
      vertical-align: middle;
    }

    .hourly-table tr + tr td {
      border-top: 1px solid var(--c-outline-muted);
    }

    .hourly-table .col-sky { text-align: center; }

    .hourly-table .col-comfort { color: var(--c-muted); }

    .hourly-scroll {
      overflow-x: auto;
      -webkit-overflow-scrolling: touch;
      margin-top: 12px;
    }

    /* \u2500\u2500 AI briefing \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */
    .ai-overline {
      font-size: 10px;
      font-weight: 700;
      letter-spacing: 0.10em;
      text-transform: uppercase;
      color: var(--c-subtle);
      margin-bottom: 8px;
    }

    .ai-body p {
      font-size: 14px;
      line-height: 1.6;
      color: var(--c-ink);
      margin: 0 0 10px;
    }

    .ai-body p:last-child { margin-bottom: 0; }

    /* \u2500\u2500 Creative spark (Georgia serif quote) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */
    .spark-overline {
      font-size: 10px;
      font-weight: 700;
      letter-spacing: 0.12em;
      text-transform: uppercase;
      color: var(--c-brand);
      margin-bottom: 12px;
    }

    .spark-quote-mark {
      font-family: Georgia, 'Times New Roman', serif;
      font-size: 38px;
      line-height: 0.75;
      color: var(--c-brand);
      opacity: 0.22;
      margin-bottom: 4px;
    }

    .spark-text {
      font-family: Georgia, 'Times New Roman', serif;
      font-size: 15px;
      line-height: 1.7;
      color: var(--c-ink);
      font-style: italic;
    }

    /* \u2500\u2500 Daylight utility bar \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */
    .utility-bar {
      display: flex;
      align-items: center;
      justify-content: space-between;
      flex-wrap: wrap;
      gap: var(--sp-2);
    }

    .utility-bar-left {
      display: flex;
      align-items: center;
      gap: 10px;
      flex-wrap: wrap;
    }

    .utility-label {
      font-size: 10px;
      font-weight: 700;
      letter-spacing: 0.09em;
      text-transform: uppercase;
      color: var(--c-subtle);
    }

    .utility-window {
      font-size: 13px;
      font-weight: 600;
      color: var(--c-ink);
    }

    /* \u2500\u2500 Composition bullets \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */
    .bullet-list {
      list-style: none;
      padding: 0;
      margin: 0;
    }

    .bullet-list li {
      font-size: 13px;
      line-height: 1.5;
      color: var(--c-ink);
      padding-left: 14px;
      position: relative;
      margin-bottom: 6px;
    }

    .bullet-list li:last-child { margin-bottom: 0; }

    .bullet-list li::before {
      content: "\u2022";
      position: absolute;
      left: 0;
      color: var(--c-muted);
    }

    /* \u2500\u2500 Kit advisory \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */
    .kit-list {
      list-style: none;
      padding: 0;
      margin: 0;
      display: flex;
      flex-direction: column;
      gap: 6px;
    }

    .kit-list li {
      font-size: 13px;
      line-height: 1.5;
      color: var(--c-ink);
      padding-left: 16px;
      position: relative;
    }

    .kit-list li::before {
      content: "\u2022";
      position: absolute;
      left: 0;
      color: var(--c-tertiary);
    }

    /* \u2500\u2500 Location list (alternatives, long range) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */
    .location-item {
      padding-bottom: 12px;
      margin-bottom: 12px;
      border-bottom: 1px solid var(--c-outline);
    }

    .location-item:last-child {
      padding-bottom: 0;
      margin-bottom: 0;
      border-bottom: none;
    }

    .location-name {
      font-size: 16px;
      font-weight: 600;
      line-height: 1.3;
      color: var(--c-ink);
      margin-bottom: 8px;
    }

    .location-meta {
      font-size: 14px;
      line-height: 1.4;
      color: var(--c-muted);
      margin-top: 4px;
    }

    .location-note {
      font-size: 13px;
      line-height: 1.5;
      color: var(--c-muted);
      margin-top: 8px;
    }

    /* \u2500\u2500 Days ahead forecast grid \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */
    .forecast-day-heading {
      font-size: 16px;
      font-weight: 600;
      line-height: 1.3;
      color: var(--c-ink);
      margin-bottom: 8px;
    }

    .forecast-best-line {
      font-size: 14px;
      font-weight: 600;
      line-height: 1.5;
      color: var(--c-ink);
      margin-bottom: 10px;
    }

    /* \u2500\u2500 Moon context \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */
    .moon-context {
      font-size: 11px;
      color: rgba(255,255,255,0.36);
      margin-top: 6px;
      display: flex;
      align-items: center;
      gap: 4px;
    }

    /* \u2500\u2500 Footer \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */
    .page-footer {
      margin-top: 48px;
      padding-top: 20px;
      border-top: 1px solid var(--c-outline);
    }

    .footer-inner {
      max-width: var(--content-width);
      margin: 0 auto;
      display: flex;
      align-items: center;
      gap: 10px;
    }

    .footer-brand {
      font-size: 12px;
      font-weight: 700;
      letter-spacing: 0.08em;
      text-transform: uppercase;
      color: var(--c-brand);
    }

    .footer-ts {
      font-size: 12px;
      color: var(--c-subtle);
    }

    .footer-sep {
      color: var(--c-outline);
    }

    /* \u2500\u2500 Footer score key \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */
    .footer-key {
      font-size: 11px;
      line-height: 1.7;
      color: var(--c-subtle);
