  function altsTelegram(alts) {
    if (!alts || !alts.length) return "\n<i>No nearby locations score well enough today.</i>";
    return "\n" + alts.map((l) => {
      const icon = l.isAstroWin ? "\u{1F30C}" : l.bestScore >= 75 ? "\u{1F525}" : "\u2705";
      const note = l.isAstroWin ? `astrophotography${l.darkSky ? " \u2B50 dark sky" : ""}` : `best ${l.bestDayHour} \xB7 ${(l.types || []).slice(0, 2).join(", ")}`;
      return `${icon} <b>${l.name}</b> ${l.driveMins}min \u2014 [${l.bestScore}/100] ${note}`;
    }).join("\n");
  }
  function windowsTelegram(wins) {
    if (!wins || !wins.length) return "<i>No clear shooting window today.</i>";
    return wins.map((w, i) => {
      const h = w.hours?.find((x) => x.score === w.peak) || w.hours?.[0];
      const hdr = i === 0 ? "\u{1F525}" : i === 1 ? "\u{1F324}" : "\u{1F4A1}";
      const ray = (h?.crepuscular || 0) > 45 ? `  \u{1F31F} Rays ${h.crepuscular}/100` : "";
      const narrow = w.fallback ? "  [best chance]" : "";
      const range = w.start === w.end ? w.start : `${w.start}\u2013${w.end}`;
      return `${hdr} <b>${w.label}</b>  ${range}  [<b>${w.peak}</b>/100]${narrow}
   \u2601\uFE0F ${h?.ch}%hi  \u{1F441} ${h?.visK}km  \u{1F4A8} ${h?.wind}  \u{1F327} ${h?.pp}%${ray}
   <i>${(w.tops || []).join(" \xB7 ")}</i>`;
    }).join("\n\n");
  }
  function photoFiveDayTelegram(days) {
    const forecastDays = days.filter((d) => d.dayIdx >= 1).slice(0, 4);
    const lines = forecastDays.map((d) => {
      const alt = d.bestAlt ? `  \u{1F4CD}${d.bestAlt.name.split(" ")[0]}` : "";
      const confTag = d.confidence === "low" ? "?" : d.confidence === "medium" ? "~" : "";
      const label = pad(d.dayLabel, 9);
      const scoreStr = rpad(d.headlineScore ?? d.photoScore, 3);
      const b = bar(d.headlineScore ?? d.photoScore);
      const am = rpad(d.amScore ?? 0, 2);
      const pm = rpad(d.pmScore ?? 0, 2);
      const as = rpad(d.astroScore ?? 0, 2);
      return `${d.photoEmoji} ${label} ${scoreStr} ${b} \u2600${am} \u{1F307}${pm} \u{1F30C}${as}${confTag}${alt}`;
    });
    return "<code>" + lines.join("\n") + "</code>";
  }
  function cwFiveDayTelegram(days) {
    const forecastDays = days.filter((d) => d.dayIdx >= 1).slice(0, 4);
    const lines = forecastDays.map((d) => {
      const cw = d.carWash;
      const label = pad(d.dayLabel, 9);
      const window = cw.start !== "\u2014" ? `${cw.start}\u2013${cw.end}` : "    \u2014    ";
      const wind = rpad(cw.wind + "kmh", 6);
      const pp = rpad(cw.pp + "%", 4);
      return `${cw.rating} ${label} ${pad(cw.label, 5)}  ${window}  \u{1F4A8}${wind} ${cw.pp < 15 ? "\u2600\uFE0F" : cw.pp < 35 ? "\u{1F324}" : cw.pp < 60 ? "\u{1F326}" : "\u{1F327}"}${pp}`;
    });
